import { readFile, writeFile } from "node:fs/promises";
import { resolve } from "node:path";

import { describe, expect, test } from "bun:test";

const repoRoot = resolve(import.meta.dirname, "../../..");
const packageJsonPath = resolve(repoRoot, "package.json");
const workflowPath = resolve(repoRoot, ".github/workflows/ci.yml");

const generatedHeader =
  "# Generated by scripts/codegen.ts — do not hand-edit. Edit scripts/build-ci-workflow.ts instead.";

const runCodegen = async (): Promise<void> => {
  const proc = Bun.spawn({
    cmd: [process.execPath, "run", "codegen"],
    cwd: repoRoot,
    stdout: "pipe",
    stderr: "pipe",
  });

  const [exitCode, stdout, stderr] = await Promise.all([
    proc.exited,
    new Response(proc.stdout).text(),
    new Response(proc.stderr).text(),
  ]);

  expect({ exitCode, stdout, stderr }).toMatchObject({ exitCode: 0 });
};

const changedLines = (
  before: string,
  after: string,
): ReadonlyArray<{ readonly before: string; readonly after: string }> => {
  const beforeLines = before.split("\n");
  const afterLines = after.split("\n");
  const count = Math.max(beforeLines.length, afterLines.length);
  const changes: Array<{ readonly before: string; readonly after: string }> = [];

  for (let index = 0; index < count; index += 1) {
    const beforeLine = beforeLines[index] ?? "";
    const afterLine = afterLines[index] ?? "";

    if (beforeLine !== afterLine) changes.push({ before: beforeLine, after: afterLine });
  }

  return changes;
};

describe("ci workflow codegen", () => {
  test("regenerates ci.yml idempotently with the generated-file header", async () => {
    await runCodegen();

    const firstWorkflow = await readFile(workflowPath, "utf8");
    expect(firstWorkflow.startsWith(`${generatedHeader}\n`)).toBe(true);

    await runCodegen();

    expect(await readFile(workflowPath, "utf8")).toBe(firstWorkflow);
  });

  test("uses package.json engines.bun as the only Bun-version source", async () => {
    await runCodegen();

    const originalPackageJson = await readFile(packageJsonPath, "utf8");
    const originalWorkflow = await readFile(workflowPath, "utf8");
    const packageJson = JSON.parse(originalPackageJson) as { engines: { bun: string } };

    packageJson.engines.bun = ">=9.8.7";

    try {
      await writeFile(packageJsonPath, `${JSON.stringify(packageJson, null, 2)}\n`);
      await runCodegen();

      const updatedWorkflow = await readFile(workflowPath, "utf8");
      expect(changedLines(originalWorkflow, updatedWorkflow)).toEqual([
        { before: "          bun-version: 1.3.0", after: "          bun-version: 9.8.7" },
        { before: "          bun-version: 1.3.0", after: "          bun-version: 9.8.7" },
        { before: "          bun-version: 1.3.0", after: "          bun-version: 9.8.7" },
      ]);
    } finally {
      await writeFile(packageJsonPath, originalPackageJson);
      await runCodegen();
    }
  });
});
